+import { resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) {
+    return false;
+  }
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, character: string) =>
+    character.toUpperCase()
+  );
+}
+
+function flatten(
+  values: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, value] of Object.entries(values)) {
+    const name = [prefix, camelCase(key)].filter(Boolean).join(".");
+    if (isPlainObject(value)) {
+      Object.assign(result, flatten(value, name));
+    } else {
+      result[name] = value;
+    }
+  }
+  return result;
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+
+    const separator = line.indexOf("=");
+    if (separator < 1) throw new Error("Expected key=value pair.");
+
+    const key = camelCase(line.slice(0, separator).trim());
+    let value = line.slice(separator + 1).trim();
+    if (!key) throw new Error("Expected a configuration key.");
+
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error("Unterminated quoted value.");
+      }
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      values[key] = value === "true";
+      continue;
+    } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      values[key] = Number(value);
+      continue;
+    }
+    values[key] = value;
+  }
+  return values;
+}
+
+function configFileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+async function readTextFile(path: string): Promise<string | undefined> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    const { readFile } = await import("node:fs/promises");
+    return await readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" ||
+      error instanceof Deno?.errors?.NotFound) {
+      return undefined;
+    }
+    throw error;
+  }
+}
+
+function getCwd(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  return Deno?.cwd() ?? process?.cwd() ?? ".";
+}
+
+/** Load config files according to the command configuration options. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const formats = options.formats ?? [".json", ".rc"];
+  const searchPaths = options.searchPaths ?? [getCwd()];
+  const values: Record<string, unknown> = {};
+  let path: string | undefined;
+
+  for (const searchPath of searchPaths) {
+    let found = false;
+    for (const format of formats) {
+      const candidate = resolve(searchPath, configFileName(options.name, format));
+      let content: string | undefined;
+      try {
+        content = await readTextFile(candidate);
+      } catch (error) {
+        throw new ConfigParseError(candidate, error);
+      }
+      if (content === undefined) continue;
+
+      let parsed: Record<string, unknown>;
+      try {
+        const result = options.parser
+          ? options.parser(content)
+          : format === ".rc"
+          ? parseRc(content)
+          : JSON.parse(content);
+        if (!isPlainObject(result)) throw new Error("Config must be a plain object.");
+        parsed = format === ".json" ? flatten(result) : result;
+      } catch (error) {
+        throw new ConfigParseError(candidate, error);
+      }
+
+      path ??= candidate;
+      Object.assign(values, parsed);
+      found = true;
+      break;
+    }
+    if (found && !options.mergeConfigs) break;
+  }
+
+  return { path, values };
+}
