    (_, character: string) => character.toUpperCase(),
  );
}

export function flattenConfigValues(
  values: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(values)) {
    const name = [prefix, camelCase(key)].filter(Boolean).join(".");
    if (isPlainObject(value)) {
      Object.assign(result, flattenConfigValues(value, name));
    } else {
      result[name] = value;
    }
  }
  return result;
}

function parseRc(content: string): Record<string, unknown> {
  const values: Record<string, unknown> = {};
  for (const line of content.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;

    const separator = line.indexOf("=");
    if (separator < 1) throw new Error("Expected key=value pair.");

    const key = camelCase(line.slice(0, separator).trim());
    let value = line.slice(separator + 1).trim();
    if (!key) throw new Error("Expected a configuration key.");

    if (value.startsWith('"')) {
      if (!value.endsWith('"') || value.length === 1) {
        throw new Error("Unterminated quoted value.");
      }
      value = value.slice(1, -1);
    } else if (value === "true" || value === "false") {
      values[key] = value === "true";
      continue;
    } else if (value !== "" && /^[-+]?(?:\d+\.?\d*|\.\d+)$/.test(value)) {
      values[key] = Number(value);
      continue;
    }
    values[key] = value;
  }
  return values;
}

function configFileName(name: string, format: string): string {
  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
}

